/// Set to 64 blocks based on analysis of execution layer trade-offs:
/// - Pipeline execution time (~13.8s) stays well under consensus message timeout window
/// - Triggers pipeline only when batch mode provides meaningful efficiency gains (>28%)
/// - Handles 95-97% of typical gaps in responsive live sync mode
/// - Maintains healthy memory utilization (25% of block buffer capacity)
pub(crate) const MIN_BLOCKS_FOR_PIPELINE_RUN: u64 = 64;

) -> Result<PayloadStatus, InsertBlockFatalError> {
    let (block, error) = error.split();

    // Temporary ONNX model unavailability: return SYNCING instead of INVALID.
    // The block is NOT added to the invalid_headers cache, allowing retry
    // once the model is downloaded. The CL advances forkchoice and the EL
    // catches up via backfill sync.
    #[cfg(feature = "async-context")]
    if matches!(
        &error,
        InsertBlockErrorKind::Execution(reth_errors::BlockExecutionError::Validation(
            reth_errors::BlockValidationError::OnnxModelUnavailableForVerification { .. }
        ))
    ) {
        warn!(
            target: "engine::tree",
            block_hash = %block.hash(),
            block_number = block.number(),
            %error,
            "ONNX model temporarily unavailable during verification, returning SYNCING"
        );
